import java.io.*;import java.util.*;class Solution{public static int n,m;public static Node[] $a;public static int[][] $b;public static int[][] dp;public static int min;public static void main(String[] args)throws IOException{StringBuffer sb = new StringBuffer("");BufferedReader br = new BufferedReader(new InputStreamReader(System.in));int T = Integer.parseInt(br.readLine());for(int $c =1;$c<= T;$c++){n = Integer.parseInt(br.readLine());$a = new Node[n+2];$b = new int[n+2][n+2];dp = new int[n+1][1<<n];StringTokenizer st = new StringTokenizer(br.readLine());for(int i =0;i<n+2;i++){int $d = Integer.parseInt(st.nextToken());int $e = Integer.parseInt(st.nextToken());$a[i] = new Node($d,$e);}Node $f = $a[1];$a[1] = $a[n + 1];$a[n + 1] = $f;for(int i =0;i<n;i++){for(int j =0;j<(1<<n);j++)dp[i][j] = 999999;}for(int i =0;i<n+2;i++){for(int j=0;j<=i;j++){if(i==j)continue;else{$b[i][j] = $b[j][i] = Math.abs($a[i].x-$a[j].x)+Math.abs($a[i].y-$a[j].y);}}}for(int i =0;i<n;i++){dp[i][1<<i] = $b[0][i+1];}for(int i =1;i<(1<<n);i++){for(int j = 0;j<n;j++){if((i &(1<<j))==0){for(int k=0;k<n;k++){if((i &(1<<k))>0){dp[j][i|(1<<j)] = Math.min(dp[j][i|(1<<j)],dp[k][i] + $b[k+1][j+1]);}}}}}int min=999999;for(int i =0;i<n;i++){min = Math.min(min,dp[i][(1<<n)-1] + $b[i+1][n+1]);}sb.append("#").append($c).append(" ").append(min).append("\n");}System.out.println(sb);}}class Node{int x;int y;Node(int x,int y){this.x=x;this.y=y;}}